mapper.update:
		/* wif-das-interface-sql-oracle.xml - updateNewReleaseCodeInfo - Robot DAS 박스추가 신규 릴리즈코드,송장번호,박스사이즈 UPDATE SQL */
		UPDATE TWIF_ROBDAS_BOXADD_ORDER
		   SET OBHDKEY 		= #{obHdKey}
			   ,WBLNO 		= #{wblNo}
			   ,PCKGBOXSIZE = #{pckgBoxSize}
   			   ,UPDATEDATE 	= #{sysdate}
			   ,UPDATEURKEY = #{surkey}
		 WHERE WASEQ 		= #{waSeq}
		   AND BFOBHDKEY 	= #{bfObHdKey}
		   AND BFWBLNO 		= #{bfWblNo}

/* wif-das-interface-sql-oracle.xml - updateRobDasAddBoxWaveResponse -  Robot DAS 박스추가 Wave I/F 항목 UPDATE SQL */
UPDATE TWIF_ROBDAS_BOXADD_WA
   SET IFSTATUS		= #{ifStatus}
	   ,IFERRCD		= #{ifErrCd}
	   ,IFERRMSG	= #{ifErrMsg}
	   ,IFPRCSDATE	= #{sysdate}
	   ,UPDATEDATE  = #{sysdate}
	   ,UPDATEURKEY = #{surkey}
 WHERE WASEQ 		= #{waSeq}
   AND CTKEY        = #{ctKey}
   AND OWKEY        = #{owKey}

/* wif-das-interface-sql-oracle.xml - updateIfResult - I/F 처리결과 UPDATE WIF 공통 SQL */
UPDATE ${tableName}
   SET IFSTATUS		= #{ifStatus}
	   ,IFERRCD		= #{ifErrCd}
	   ,IFERRMSG	= #{ifErrMsg}
	   ,IFPRCSDATE	= #{sysdate}
	   ,UPDATEDATE  = #{sysdate}
	   ,UPDATEURKEY = #{surkey}
 WHERE WASEQ 		= #{waSeq}
   AND WAHDKEY		= #{waHdKey}
   AND CTKEY        = #{ctKey}
   AND OWKEY        = #{owKey}
